/**
 * Loads content and technique JSON data generated by the build script.
 */

let cachedData = null;

export async function loadData() {
  if (cachedData) return cachedData;

  const [contentRes, techniquesRes] = await Promise.all([
    fetch('data/content.json'),
    fetch('data/techniques.json'),
  ]);

  const content = await contentRes.json();
  const techniques = await techniquesRes.json();

  // Build technique lookup map
  const techniqueMap = {};
  for (const t of techniques) {
    techniqueMap[t.id] = t;
  }

  cachedData = { content, techniques, techniqueMap };
  return cachedData;
}

/**
 * Get today's assigned pieces.
 * Priority: pieces assigned to today's date, then resurfaced skipped pieces, then queue.
 */
export function getTodayPieces(data, progress) {
  const today = new Date().toISOString().slice(0, 10);
  const completedIds = new Set(
    progress.items.filter(p => p.status === 'completed').map(p => p.id)
  );
  const skippedMap = new Map(
    progress.items.filter(p => p.status === 'skipped').map(p => [p.id, p])
  );

  const available = data.content.filter(p => !completedIds.has(p.id));

  // 1. Date-assigned pieces for today
  const dateAssigned = available.filter(p =>
    p.assignment && p.assignment.date === today && !skippedMap.has(p.id)
  );

  if (dateAssigned.length > 0) return dateAssigned;

  // 2. Resurfaced skipped pieces
  const usageDays = progress.usage_days || 0;
  const resurfaced = available.filter(p => {
    const skip = skippedMap.get(p.id);
    return skip && usageDays >= skip.resurface_at_usage_day;
  });

  if (resurfaced.length > 0) return resurfaced.slice(0, 3);

  // 3. Queue-ordered pieces (not skipped, changed pieces go to end)
  const changedIds = new Set(
    progress.items.filter(p => p.status === 'changed').map(p => p.id)
  );
  const queued = available
    .filter(p => p.assignment && p.assignment.queue_position != null && !skippedMap.has(p.id))
    .sort((a, b) => {
      // Changed pieces sort after non-changed ones
      const aChanged = changedIds.has(a.id) ? 1 : 0;
      const bChanged = changedIds.has(b.id) ? 1 : 0;
      if (aChanged !== bChanged) return aChanged - bChanged;
      return a.assignment.queue_position - b.assignment.queue_position;
    });

  if (queued.length > 0) return queued.slice(0, 3);

  return [];
}
